import{findClosest}from"./lifecycle";let globalIdMemo={};export function findAndIncrementId(o){return globalIdMemo[o]||(globalIdMemo[o]=0),++globalIdMemo[o]}export function closestIdRoot(o,e){return findClosest(o,o=>{if(o._x_ids&&o._x_ids[e])return!0})}export function setIdRoot(o,e){o._x_ids||(o._x_ids={}),o._x_ids[e]||(o._x_ids[e]=findAndIncrementId(e))}